-- Organizations seed — real company registry (Companies_details.xlsx) · append-only
--
-- Seeds the 80 owner/manager firms into public.organizations (org type derived
-- from OWNS/MANAGES). No desk email/phone in the source, so those stay NULL
-- (the firewall masks contact anyway — no fabricated contacts). People are NOT
-- seeded: organization_members FKs to real auth users, and we have no member
-- names yet — the UI shows generic placeholders until real users join.
-- ════════════════════════════════════════════════════════════════════

CREATE UNIQUE INDEX IF NOT EXISTS organizations_name_key ON public.organizations (name);

